-- W2 catalog seed batch1_vegetables_roots — 16 cited profiles (generated from PlantAppPlanner scratch/catalog/profiles; sources embedded per row).
-- Upsert: already-seeded Slice-1 ids are enriched in place (version bump), never duplicated.
insert into public.plant_profiles (
  id, scientific_name, common_names, category, growth_habit, requires_support, self_fruitful, pollination_partners_required, watering_profile, feeding_profile, container_profile, light_profile, temperature_profile, seasonality, common_issues, vertical_suitability, source, version, last_reviewed_at
) values
  ('allium-fistulosum', 'Allium fistulosum', array['Green onion','Scallion','Bunching onion','Welsh onion','Japanese bunching onion']::text[], 'vegetable', 'upright', false, null, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"containerLeachAdjustment":0.7,"preferredNpk":"balanced, nitrogen-forward (e.g. 10-10-10 to 16-16-8) for leafy top growth"}'::jsonb, '{"recommendedMinLiters":7,"idealMinLiters":10,"idealMaxLiters":20,"soilMixTags":["well-draining","fertile","organic-matter-rich","moisture-retentive"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-12,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"6-9":[{"startMonth":3,"endMonth":8}]},"productiveMonths":[5,6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Onion maggot bores into stems, causing plants to turn yellow and wilt (UMN Extension).','Fungal/bacterial rots: Fusarium basal rot, Botrytis neck rot, and bacterial soft rot, encouraged by overwatering and waterlogged soil (UMN Extension).','Shallow roots dry out fast; keep evenly moist and never waterlogged. Use a pot at least 6-8 inches (15-20 cm) deep with good drainage.','Weeds easily outcompete small seedlings early in the season (UMN Extension).','Perennial in USDA zones 6-9; north of zone 6 typically grown as an annual (Missouri Botanical Garden).']::text[], 0.2, '[{"citation":"University of Minnesota Extension — Growing scallions in home gardens. Full sun required; keep soil evenly moist (shallow roots); soak thoroughly at least once weekly if under 1 inch rain; sow 1/4 to 1/2 inch deep, rows 12-18 inches apart, thin to 1 inch; succession-sow every 3-4 weeks.","url":"https://extension.umn.edu/vegetables/growing-scallions-home-gardens","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing scallions in home gardens. Onions require full sun for best growth.","url":"https://extension.umn.edu/vegetables/growing-scallions-home-gardens","field":"lightProfile"},{"citation":"University of Minnesota Extension — Growing scallions in home gardens. Pests/diseases: onion maggot; Fusarium basal rot, Botrytis neck rot, bacterial soft rot; weed competition early season.","url":"https://extension.umn.edu/vegetables/growing-scallions-home-gardens","field":"commonIssues"},{"citation":"Oregon State University, Commercial Vegetable Production — Onions, Green (Bunching). Germination 46-86 F (8-30 C), optimum over 60 F (16 C); maintain top foot of soil at 65-70% of field capacity; nitrogen 50-70 lb/acre with side-dressing 75-100 lb N/acre; seeding March through mid-August; 60-70 day crop.","url":"https://horticulture.oregonstate.edu/oregon-vegetables/onions-green-bunching","field":"temperatureProfile"},{"citation":"Oregon State University, Commercial Vegetable Production — Onions, Green (Bunching). Nitrogen-driven leafy crop; side-dress additional nitrogen during growth; seeding window March through mid-August.","url":"https://horticulture.oregonstate.edu/oregon-vegetables/onions-green-bunching","field":"feedingProfile"},{"citation":"Oregon State University, Commercial Vegetable Production — Onions, Green (Bunching). Seeding March through mid-August; 60-70 day crop used for irrigation planning.","url":"https://horticulture.oregonstate.edu/oregon-vegetables/onions-green-bunching","field":"seasonality"},{"citation":"Missouri Botanical Garden Plant Finder — Allium fistulosum. Winter hardy to USDA Zones 6-9; full sun to part shade; medium water; clumping evergreen perennial, grown as annual north of Zone 6.","url":"https://www.missouribotanicalgarden.org/PlantFinder/PlantFinderDetails.aspx?taxonid=256068&isprofile=0","field":"temperatureProfile"},{"citation":"Iowa State University Extension, Yard and Garden — The Other Onions. Allium fistulosum is hardy and one of the first plants to emerge in spring; grown primarily for green tops; sow early spring and again midsummer for fall/following-spring harvest.","url":"https://yardandgarden.extension.iastate.edu/how-to/other-onions","field":"seasonality"},{"citation":"Container size estimated from extension guidance that scallions have shallow roots needing a pot 6-8 inches (15-20 cm) deep with good drainage (UMN Extension watering note plus general extension container guidance); exact liter volume is not given by a single .edu page, so recommendedMinLiters (7 L) is a conservative practical estimate for a 6-inch-deep, ~25 cm-wide pot.","url":"https://extension.umn.edu/vegetables/growing-scallions-home-gardens","field":"confidence"},{"citation":"coldHardyMinC (-12 C) is a conservative value: Missouri Botanical Garden lists USDA Zones 6-9 (Zone 6 minimum approx -23 to -18 C), but reliable garden overwintering of green tops is more conservative; RHS hardiness rating H5 (-15 to -10 C) for Welsh onion supports roughly -12 C as a safe operating floor for keeping plants productive rather than absolute survival.","url":"https://www.rhs.org.uk/plants/26473/allium-fistulosum/details","field":"confidence"},{"citation":"feedingProfile.baseIntervalDays (21 days) estimated: Oregon State specifies total seasonal nitrogen and side-dressing for field/acre but no home-garden day interval; 3-week feeding cadence is a conservative translation for a fast leafy nitrogen-hungry crop.","url":"https://horticulture.oregonstate.edu/oregon-vegetables/onions-green-bunching","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('allium-sativum', 'Allium sativum', array['Garlic']::text[], 'vegetable', 'upright', false, null, 0, '{"baseIntervalDays":4,"dryingTolerance":"medium","overwaterRisk":"high","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"postHarvestIntervalDays":21,"containerLeachAdjustment":0.75,"preferredNpk":"high-nitrogen, low/no-phosphorus (e.g. 30-0-10 or 21-0-0) before and at shoot emergence; stop nitrogen by early May"}'::jsonb, '{"recommendedMinLiters":15,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-drained","fertile","loamy","ph-6.0-7.0"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":12}'::jsonb, '{"coldHardyMinC":-10,"heatStressC":30,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"cold-temperate":[{"startMonth":9,"endMonth":11}]},"productiveMonths":[6,7],"dormancyMonths":[12,1,2]}'::jsonb, array['Overwatering and poorly drained soil cause bulb rot and fungal disease; garlic prefers consistent but not soggy moisture.','Stop watering about two weeks before harvest to avoid staining bulb wrappers and disease.','Critical bulbing period (mid-spring to early summer) needs steady moisture; drying out then reduces bulb size.','Avoid applying nitrogen after the first week of May (per UMN); late nitrogen delays bulbing.','Container minimum (15 L) assumes a pot at least 20 cm / 8 in deep for a small cluster of cloves; deeper/wider pots give larger bulbs and hold more plants.','Hardneck types are hardier than softneck; the cold-hardy minimum cited reflects RHS H4 (-10 to -5 C) and is conservative for well-mulched hardneck garlic, which survives much colder Minnesota winters under mulch.']::text[], 0, '[{"citation":"University of Minnesota Extension — Growing garlic in home gardens. Planting depth 2-3 in, cloves ~6 in apart, plant in fall after first killing frost; water at least 1 inch per week, stop two weeks before harvest; soil pH 6.0-7.0; moderate-to-high nitrogen, top-dress at shoot emergence and 2-3 weeks later, avoid nitrogen after first week of May (examples 30-0-10, 24-0-15); harvest late June to late July.","url":"https://extension.umn.edu/vegetables/growing-garlic","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing garlic in home gardens. Nitrogen feeding: top-dress as soon as shoots emerge then again 2-3 weeks afterward; low/no-phosphorus high-nitrogen products (30-0-10, 24-0-15); avoid nitrogen after first week in May.","url":"https://extension.umn.edu/vegetables/growing-garlic","field":"feedingProfile"},{"citation":"University of Minnesota Extension — Growing garlic in home gardens. Soil pH between 6.0 and 7.0; well-drained fertile soil; planting depth 2-3 inches; fall planting one to two weeks after first killing frost.","url":"https://extension.umn.edu/vegetables/growing-garlic","field":"seasonality"},{"citation":"Clemson Cooperative Extension HGIC — Onion, Leek, Shallot & Garlic. Garlic grows best in full sun; soil pH 6.2-6.5; consistent soil moisture especially critical during bulbing; planted in fall; pre-plant 5-10-10 plus sulfur, followed by calcium nitrate (15.5-0-0) side-dressings through winter into spring; harvest when leaves yellow in early summer.","url":"https://hgic.clemson.edu/factsheet/onion-leek-shallot-garlic/","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC — Onion, Leek, Shallot & Garlic. Spacing 3-5 inches apart, 12-24 inches between rows; consistent moisture critical during the bulbing period.","url":"https://hgic.clemson.edu/factsheet/onion-leek-shallot-garlic/","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS) — Allium sativum (garlic). Position full sun; hardiness H4, minimum temperature -10 to -5 C; well-drained soil (chalk, loam, sand), alkaline to neutral; harvest from early summer once leaves turn yellow; cloves 15 cm apart, tip 2.5 cm below surface, rows 30 cm apart.","url":"https://www.rhs.org.uk/plants/858/i-allium-sativum-i/details","field":"temperatureProfile"},{"citation":"Utah State University Extension — Garlic in the Garden. Plant largest cloves pointed-end up 2-3 inches deep; space 3-4 inches apart, rows 6-10 inches apart; moisten soil thoroughly to a depth of 12 inches; shallow roots make consistent watering critical; side-dress nitrogen (21-0-0) in mid-April and late May.","url":"https://extension.usu.edu/yardandgarden/research/garlic-in-the-garden","field":"feedingProfile"},{"citation":"Confidence note: targetSunHours (8 h) and minSunHours (6 h) are derived from the universal extension/RHS recommendation of ''full sun'' (no source gives an exact hour count); 6+ h is the standard horticultural definition of full sun. baseIntervalDays of 4 is a conservative interpretation of UMN''s ''1 inch/week thorough soaking'' and the bulbing-period ''every 3-5 days'' guidance (no single canonical interval published). heatStressC (30 C) and the container minimum (15 L) are conservative estimates: garlic bulbing is impaired by high summer heat per multiple extensions, and no .edu source publishes an exact heat-stress threshold or a precise minimum container volume in liters. coldHardyMinC uses the conservative RHS H4 floor (-5 to -10 C) even though mulched hardneck garlic survives colder; field-grown Minnesota garlic tolerates well below this.","url":"https://extension.umn.edu/vegetables/growing-garlic","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('beta-vulgaris', 'Beta vulgaris', array['Beet','Beetroot','Garden beet','Table beet']::text[], 'root', 'rosette', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":28,"containerLeachAdjustment":0.5,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":11,"idealMinLiters":20,"idealMaxLiters":40,"soilMixTags":["well-drained","fertile-loam","loose-stone-free","ph-6.0-7.0"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-3,"heatStressC":24,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"us-clemson-piedmont":[{"startMonth":3,"endMonth":3},{"startMonth":8,"endMonth":8}],"us-clemson-central":[{"startMonth":2,"endMonth":2},{"startMonth":8,"endMonth":8}],"us-clemson-coastal":[{"startMonth":12,"endMonth":1},{"startMonth":8,"endMonth":8}],"uk-rhs":[{"startMonth":3,"endMonth":7}]},"productiveMonths":[5,6,7,8,9,10],"dormancyMonths":[12,1]}'::jsonb, array['Inconsistent watering causes roots to split or crack; keep soil evenly moist (RHS).','Hot, dry weather above ~24C can trigger bolting (premature flowering) and woody roots (RHS, UC IPM).','Pests and diseases: aphids, leafminers/beet leaf miner, flea beetles, webworms, Cercospora leaf spot, damping-off, root-knot nematodes (Clemson, RHS).','Internal black spot indicates boron deficiency; have soil tested before adding boron (Clemson).','Beets do not transplant well; direct-sow into the final container or bed (Illinois Extension, UC IPM).','Container minimum: choose round (globe) varieties and a pot at least ~25cm/10in deep (~11 L, ~3 gal) per Illinois Extension; RHS recommends 40cm wide and deep for best results. Beet seed is a cluster of 2-4 seeds, so thin seedlings to 3-4in apart.']::text[], 0.1, '[{"citation":"Clemson Cooperative Extension HGIC 1322 ''Carrot, Beet, Radish & Parsnip'' — spacing, days to maturity (50-70), 5-10-10 fertilizer at planting and sidedress when plants reach 4 inches, full sun, uniform moisture to 6-inch depth, pests/diseases, boron/internal black spot, planting dates by SC region.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC 1322 — SC planting windows (Piedmont Mar/Aug, Central Feb/Aug, Coastal Dec-Jan/Aug) and full-sun requirement.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"seasonality"},{"citation":"Clemson Cooperative Extension HGIC 1322 — beets require full sun for optimal growth and yield; common pests, diseases and disorders.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"commonIssues"},{"citation":"RHS ''How to grow Beetroot'' — sow late Mar/Apr-Jul; water seedlings regularly in dry spells and every 10-14 days during dry periods once established; inconsistent watering splits roots, excess water favors leaves over roots; sunny well-drained site; soil min 7C (45F) for germination; container minimum pot 40cm wide and deep with round-root varieties; bolting and woody roots in hot/dry weather; beet leaf miner, downy mildew.","url":"https://www.rhs.org.uk/vegetables/beetroot/grow-your-own","field":"wateringProfile"},{"citation":"RHS ''How to grow Beetroot'' — container growing: minimum pot 40cm (16in) wide and deep, peat-free multi-purpose compost, choose rounded-root varieties.","url":"https://www.rhs.org.uk/vegetables/beetroot/grow-your-own","field":"containerProfile"},{"citation":"UC IPM ''Cultural Tips for Growing Beets'' — germination soil temp minimum 41F (5C), optimal 50-86F (10-30C); days to maturity 42-70; needs at least 4 to 6 hours of full sunlight; plants tolerate frosts and mild freezes; high temperatures cause rapid growth and white rings; frequent light irrigation when small; California planting months by region.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-beets/","field":"lightProfile"},{"citation":"UC IPM ''Cultural Tips for Growing Beets'' — beets tolerate frosts and mild freezes (cool-season crop); high temperatures degrade root quality, informing heatStressC ~24C as the upper comfortable limit before bolting/quality loss.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-beets/","field":"temperatureProfile"},{"citation":"Illinois Extension ''Small-space containers big with new gardeners'' / container guidance — beets and other root/leafy crops need at least ~10 inches of container depth (a 10-inch / ~3-gallon, ~11 L pot); most plants need 6-8 inches for root growth; beets direct-seeded as they do not transplant well.","url":"https://extension.illinois.edu/news-releases/small-space-containers-big-new-gardeners","field":"containerProfile"},{"citation":"The Old Farmer''s Almanac ''How to Plant, Grow, and Harvest Beets'' — water about 1 inch per square foot per week; cool-season crop best at ~60-65F; at least 6 hours direct sun; soil pH 6.5-7; days to maturity ~55-70.","url":"https://www.almanac.com/plant/beets","field":"wateringProfile"},{"citation":"Confidence note — coldHardyMinC set to -3C as a conservative cool-season frost-tolerance figure. Sources (UC IPM, Almanac) describe beets as cool-season crops that ''tolerate frosts and mild freezes'' but give no exact lethal low temperature for the plant, so this is an estimate. heatStressC (24C) is inferred from RHS/UC IPM bolting-and-woody-root warnings in hot weather rather than a single published threshold. hotWeatherMultiplier (1.5x) and rainSkipThresholdMm (12mm) are app-tuning defaults derived from the ~1in/week and dry-spell watering guidance, not directly published numbers.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-beets/","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('beta-vulgaris-cicla', 'Beta vulgaris cicla', array['Swiss chard','Chard','Silverbeet','Leaf beet']::text[], 'vegetable', 'upright', false, null, 0, '{"baseIntervalDays":4,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"postHarvestIntervalDays":14,"containerLeachAdjustment":0.7,"preferredNpk":"low- or no-phosphorus unless a soil test indicates otherwise; a balanced or higher-nitrogen feed supports continued leafy regrowth, especially in containers"}'::jsonb, '{"recommendedMinLiters":11,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["moderately-fertile","compost-amended","well-draining","moisture-retentive","ph-6.0-7.0"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-3,"heatStressC":27,"frostSensitive":false}'::jsonb, '{"productiveMonths":[6,7,8,9,10],"dormancyMonths":[12,1,2]}'::jsonb, array['Cool-season leafy green: grows best around 10-24C (50-75F). It bolts (runs to seed) when stressed by heat or by an early cold spell after transplanting, which ends leaf production; sow in spring once cold-bolting risk has passed, and again in summer for a fall crop.','Needs consistent, even soil moisture (about 25mm / 1 inch of water per week). Letting it dry out repeatedly encourages bolting and bitter leaves; in containers and hot weather it may need watering every day or two.','Frost-hardy, not frost-sensitive: tolerates light frost and can overwinter in mild climates, but new-leaf production stops in cold weather. coldHardyMinC of about -3C is a conservative light-frost figure; established plants under cover tolerate harder freezes.','Light feeder. Per UMN Extension use a low- or no-phosphorus fertilizer unless a soil test says otherwise; soil enriched with compost may need little or no extra feeding (RHS).','Common problems: Cercospora leaf spot (reddish-purple leaf spots), leaf miners (beet leaf miner), downy mildew, grey mould, and slugs and snails.','Container minimum of ~11L (3 gal) suits a single plant; a larger pot at least ~40cm (16in) wide and deep, roughly 19-38L, holds moisture better and supports several plants or sustained cut-and-come-again harvest.']::text[], 0.2, '[{"citation":"University of Minnesota Extension - Growing spinach and Swiss chard in home gardens. Direct seed four to six inches apart in rows 18 to 30 inches apart; plant early to mid-May to avoid cold-induced bolting, or sow indoors ~4 weeks before transplanting and again in June for a fall crop; needs one inch of rain/water each week for best results (sandy soil more often); soil pH as low as 6.0 tolerated; use low- or no-phosphorus fertilizer unless a soil test recommends otherwise; biennial that won''t flower until after winter and can be protected from freezing with floating row cover; problems include Cercospora leaf spot, leafminers, slugs, snails, and cutworms.","url":"https://extension.umn.edu/vegetables/growing-spinach-and-swiss-chard","field":"wateringProfile"},{"citation":"University of Minnesota Extension - Growing spinach and Swiss chard in home gardens. Light feeder: use a low- or no-phosphorus fertilizer unless a soil test recommends otherwise; improve soil with well-rotted manure or compost; apply phosphorus and potassium only per soil test.","url":"https://extension.umn.edu/vegetables/growing-spinach-and-swiss-chard","field":"feedingProfile"},{"citation":"RHS - How to grow chard. Position: full sun, or with some light shade in summer. Water young plants regularly until established; mature plants are fairly drought tolerant but need watering in long dry spells, and container plants need regular watering throughout growth. Chard doesn''t usually need feeding - it grows well in most soils or fresh potting compost. Containers: minimum about 40cm (16in) wide and deep. Spacing 30cm apart (5cm for baby salad leaves). Hardy: survives winter outdoors without protection but stops producing new leaves once temperatures drop. Problems: beet leaf miner, downy mildews, grey mould, slugs and snails.","url":"https://www.rhs.org.uk/vegetables/chard/grow-your-own","field":"containerProfile"},{"citation":"RHS - How to grow chard. Recommended position is full sun, or some light shade in summer, which for a leafy green corresponds to roughly 4-8 hours of direct sun (chard tolerates partial shade better than fruiting crops).","url":"https://www.rhs.org.uk/vegetables/chard/grow-your-own","field":"lightProfile"},{"citation":"Clemson Cooperative Extension HGIC - Swiss Chard. Can be sown directly in the garden in spring or late summer and takes 40 to 45 days to reach maturity; harvest outer leaves in cut-and-come-again fashion when they reach between 4 and 12 inches in length.","url":"https://hgic.clemson.edu/swiss-chard/","field":"seasonality"},{"citation":"University of Illinois Extension - Chard. Direct seed in early to mid-spring or start indoors; sow 1/2 to 3/4 inch deep; thin to 4 to 6 inches apart (or 9 to 12 inches for large plants); maintain sufficient soil moisture to keep plants growing well; harvest outer leaves young and tender at about 8-12 inches long.","url":"https://extension.illinois.edu/gardening/chard","field":"wateringProfile"},{"citation":"Seed-germination and growth temperatures synthesized from UMN Extension (room temperature is good for germination) and horticultural guidance: chard germinates well near 16-18C (60-65F) and thrives at about 10-24C (50-75F). Modeled thermal thresholds: coldHardyMinC ~ -3C reflects ''tolerates light frost / hardy'' (no per-degree extension figure is published, so this is a conservative estimate); heatStressC ~ 27C reflects that growth slows and bolting risk rises in summer heat above the ~24C upper of its preferred range. frostSensitive is set false because extension/RHS sources describe chard as frost-hardy. These exact degree thresholds are estimates, not directly extension-sourced.","url":"https://extension.umn.edu/vegetables/growing-spinach-and-swiss-chard","field":"confidence"},{"citation":"Container sizing: RHS gives a minimum container of about 40cm (16in) wide and deep for chard; US extension services do not publish a single authoritative liter figure. recommendedMinLiters ~11L (a 3-gallon pot for one plant), idealMinLiters ~19L, and idealMaxLiters ~38L are conservative estimates reconciling the RHS 40cm minimum with typical single-plant container practice. lightProfile sun-hours (target 6, min 4, max 8) are derived from the RHS ''full sun or some light shade'' qualitative guidance rather than a stated hours figure.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('brassica-oleracea-acephala', 'Brassica oleracea (Acephala)', array['Kale','Borecole','Leaf kale']::text[], 'vegetable', 'upright', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":21,"preferredNpk":"10-3-1"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":21,"idealMaxLiters":30,"soilMixTags":["loamy","well-drained","rich-organic-matter","ph-6.0-7.5"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-7,"heatStressC":27,"frostSensitive":false}'::jsonb, '{"productiveMonths":[3,4,5,9,10,11,12],"dormancyMonths":[7,8]}'::jsonb, array['Container minimum (~19 L) reflects RHS guidance of a pot at least 30 cm (12 in) wide and deep for one plant; choose a compact cultivar (e.g. ''Dwarf Green Curled'') for container culture.','Bolts and turns bitter in summer heat; best grown as a cool-season spring and fall/autumn crop. Frost actually sweetens the leaves.','Susceptible to cabbage-family pests (cabbage worms, aphids, flea beetles) as a Brassica.','Keep soil consistently moist (about 1 inch / 25 mm of water per week); sandy soils need more frequent watering.']::text[], 0.1, '[{"citation":"UMN Extension — Growing collards and kale in home gardens: watering ''1 inch of rainfall per week is good'', sandy soils need more frequent watering.","url":"https://extension.umn.edu/vegetables/growing-collards-and-kale","field":"wateringProfile"},{"citation":"UMN Extension — Growing collards and kale: feeding when plants reach ~4 in tall, e.g. 3-1/2 cups 10-3-1 per 100 ft of row; cold tolerant and keeps producing well beyond first fall frosts; neutral soil pH 6.0 to 7.5 ideal.","url":"https://extension.umn.edu/vegetables/growing-collards-and-kale","field":"feedingProfile"},{"citation":"UMN Extension — Growing collards and kale: neutral soil pH 6.0 to 7.5 ideal; loamy, well-drained soil with high organic matter.","url":"https://extension.umn.edu/vegetables/growing-collards-and-kale","field":"containerProfile"},{"citation":"Clemson HGIC — ''Kale Is a Headless Cabbage'': needs at least six hours of sun; germinates at soil temps 40-85 F; grows well above 50 F; leaves hardy to 20 F (about -7 C).","url":"https://hgic.clemson.edu/kale-is-a-headless-cabbage/","field":"lightProfile"},{"citation":"Clemson HGIC — ''Kale Is a Headless Cabbage'': leaves hardy to 20 F (-6.7 C, rounded to -7 C); grows well when temperatures stay above 50 F.","url":"https://hgic.clemson.edu/kale-is-a-headless-cabbage/","field":"temperatureProfile"},{"citation":"RHS — How to grow Kale: use a large container at least 30 cm (12 in) wide and deep for one plant; choose compact cultivars for containers; container plants need regular watering; feeding usually only needed on poor soils or in containers (nitrogen-rich feed).","url":"https://www.rhs.org.uk/vegetables/kale/grow-your-own","field":"containerProfile"},{"citation":"RHS — How to grow Kale: hardy leafy vegetable cropping from September onwards through the coldest months; likes sun but copes in light shade.","url":"https://www.rhs.org.uk/vegetables/kale/grow-your-own","field":"seasonality"},{"citation":"Old Farmer''s Almanac — Kale: cool-weather crop, plant 4-6 weeks before last spring frost and ~3 months before first fall frost; continues growing until ~20 F (-7 C); flavor improves after a light frost; can turn bitter in summer heat.","url":"https://www.almanac.com/plant/kale","field":"seasonality"},{"citation":"Confidence note: heatStressC (27 C / ~80 F) is a conservative estimate. Sources (RHS, Almanac) state kale turns bitter and is prone to bolting in summer heat/strong sun but give no single numeric heat-stress threshold; hotWeatherMultiplier and feeding baseIntervalDays are also derived/estimated from the qualitative ''1 inch/week'' and per-row fertilizer guidance rather than published container intervals.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('brassica-oleracea-italica', 'Brassica oleracea (Italica Group)', array['Broccoli','Calabrese']::text[], 'vegetable', 'upright', true, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"containerLeachAdjustment":0.5,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["rich","well-drained","high-organic-matter"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-3,"heatStressC":25,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"cool-spring":[{"startMonth":3,"endMonth":4}],"fall":[{"startMonth":7,"endMonth":9}]},"productiveMonths":[5,6,9,10,11]}'::jsonb, array['Bolting (premature flowering) when exposed to prolonged heat above ~25-29C or, for spring crops, 10+ consecutive days of 2-10C cold after establishment.','Poor or hollow crown development in hot weather (above ~30C day / 25C night).','Head rot if developing heads stay wet; avoid overhead watering on the crown.','Cabbage-family pests (cabbage worms, aphids, flea beetles) are common.','Container minimum of ~19 L (5 gal, ~30 cm wide and deep) is the smallest practical pot; one plant per container. Larger pots give a bigger main head.']::text[], 0.1, '[{"citation":"University of Minnesota Extension — Growing broccoli in home gardens. Watering: soak soil at least once a week if it does not receive 1 inch of rain; transplant starter solution high in phosphorus and low in nitrogen; side-dress when plants are 4 inches tall; spacing 8-10 inches; spring varieties 50-60 days, fall 60-85 days; tolerates first light fall frosts; crown problems in hot weather (86F day / 77F night).","url":"https://extension.umn.edu/vegetables/growing-broccoli","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing broccoli in home gardens. Feeding/fertilizer schedule and planting windows (spring seed early-mid April, fall seed early-late July).","url":"https://extension.umn.edu/vegetables/growing-broccoli","field":"feedingProfile"},{"citation":"University of Minnesota Extension — Growing broccoli in home gardens. Hot weather (86F day / 77F night) causes crown development problems; some cold tolerance, continues growth after first light fall frosts.","url":"https://extension.umn.edu/vegetables/growing-broccoli","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC — Broccoli. Prefers average temperatures of 65-75F; pre-plant 10-10-10 at 2.5 lb/100 sq ft, side-dress calcium nitrate (15.5-0-0) 3-4 weeks after transplant; water to moisten soil 6 inches deep, avoid light sprinklings; spacing 18-24 in within rows 3 ft apart; 50-90 days to maturity; bolting after 10+ days of 35-50F.","url":"https://hgic.clemson.edu/factsheet/broccoli/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC — Broccoli. Optimal air temperature 65-75F; spring transplants must be protected from freezing; bolting trigger 35-50F for 10+ days.","url":"https://hgic.clemson.edu/factsheet/broccoli/","field":"temperatureProfile"},{"citation":"UC IPM (UC ANR) — Cultural Tips for Growing Broccoli. Vegetables do best with full sunlight (at least 4-6 hours/day); best growth 60-65F average air temperature, germinates ~70F, struggles above 77-86F; nitrogen 0.5-1 lb/100 ft row, side-dress every 3-4 weeks once plants are 3-4 in tall; avoid wetting foliage; spacing 9-12 in in rows 3 ft apart.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-broccoli/","field":"lightProfile"},{"citation":"UC IPM (UC ANR) — Cultural Tips for Growing Broccoli. Best growth at 60-65F; tolerates minimum growth conditions ~41F; struggles / bolts above 77-86F.","url":"https://ipm.ucanr.edu/home-and-landscape/cultural-tips-for-growing-broccoli/","field":"temperatureProfile"},{"citation":"Royal Horticultural Society (RHS) — How to grow broccoli. Grows best in sun or very light shade; established plants need watering only in prolonged dry weather, water young plants in dry spells; apply high-nitrogen feed when plants are ~20 cm (8 in) tall on poor soil; plants grow 60-90 cm tall and usually need support (mound soil around base and/or insert a cane), especially in exposed sites; spacing 60-80 cm.","url":"https://www.rhs.org.uk/vegetables/broccoli/grow-your-own","field":"requiresSupport"},{"citation":"The Old Farmer''s Almanac — Growing Broccoli. Container growing: use at least a 5-gallon container at least 12 inches in diameter and 12 inches deep; space plants 18-24 inches apart. (5 gal = ~19 L.)","url":"https://www.almanac.com/plant/broccoli","field":"containerProfile"},{"citation":"Confidence note: targetSunHours/min/max are derived from UC IPM''s general vegetable guidance of ''full sun, at least 4-6 hours/day'' rather than a broccoli-specific full-sun hour figure (most sources state ''full sun'' qualitatively). Values set conservatively (6 target, 4 min, 8 max). hotWeatherMultiplier (1.5) and rainSkipThresholdMm (25 mm ~= 1 in/week) are app-level care heuristics inferred from the ~1 inch/week and avoid-drought guidance, not directly published numbers. coldHardyMinC=-3 reflects ''tolerates ~27-28F, damage below ~25F'' synthesized from extension guidance; feeding baseIntervalDays=21 generalizes the 3-4 week side-dress interval.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('capsicum-annuum', 'Capsicum annuum', array['Bell pepper','Sweet pepper','Pepper']::text[], 'vegetable', 'bush', true, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":2,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"fruitingIntervalDays":7,"preferredNpk":"high-potassium (low-N fruiting feed, e.g. tomato feed); side-dress calcium nitrate 15.5-0-0 in-ground"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-drained","soilless-potting-mix","compost-enriched"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6}'::jsonb, '{"coldHardyMinC":12,"heatStressC":30,"frostSensitive":true}'::jsonb, '{"productiveMonths":[7,8,9,10]}'::jsonb, array['Blossom-end rot from inconsistent soil moisture / poor calcium uptake — keep moisture even.','Flower/bud drop in hot days-and-nights or under drought stress.','Sunscald on fruit borne on small or sparsely-foliaged plants.','Over-fertilizing (too much nitrogen) yields lush foliage but fewer flowers and fruit.','Container plants dry out fast and may need daily watering in hot weather; minimum ~19 L (5 gal) pot recommended.','Aphids, cutworms, hornworms, bacterial leaf spot, and (greenhouse) spider mite / whitefly / grey mould.','Heavy fruit set can break stems; staking or caning recommended.']::text[], 0.2, '[{"citation":"UMN Extension — Growing peppers. Spacing 18 in apart; soak soil thoroughly at least once a week / ~1 in rain weekly; transplant after night lows above 50°F (10°C), avoid <60°F or >70°F; blossom-end rot, flower drop, sunscald, aphids/cutworms/hornworms.","url":"https://extension.umn.edu/vegetables/growing-peppers","field":"wateringProfile,temperatureProfile,commonIssues,seasonality"},{"citation":"Clemson HGIC — Pepper. Optimal day 70-85°F (21-29°C), night 60-70°F (16-21°C); uniform moisture, moisten soil ≥6 in deep, do not let soil dry between waterings; side-dress 3-4 weeks after planting then again 3-4 weeks later (calcium nitrate 15.5-0-0); over-fertilizing reduces blooms; blossom-end rot, bacterial leaf spot, anthracnose; 70-85 days to harvest from transplant.","url":"https://hgic.clemson.edu/factsheet/pepper/","field":"feedingProfile,temperatureProfile,wateringProfile,commonIssues"},{"citation":"RHS — How to grow sweet peppers. Containers at least 30 cm wide per plant; once flowering, feed weekly with high-potassium liquid fertiliser; tolerates min ~12°C, prefers ≥15°C, fruiting reduced above 30°C; container plants may need daily watering in hot, dry weather; bamboo-cane support for heavy fruit; aphids, blossom-end rot, spider mite, whitefly, grey mould.","url":"https://www.rhs.org.uk/vegetables/peppers/grow-your-own","field":"containerProfile,feedingProfile,temperatureProfile,requiresSupport,wateringProfile,commonIssues"},{"citation":"The Old Farmer''s Almanac — Growing Bell Peppers. Full sun, 6-8 hours of direct sun per day; grow in well-drained soil or containers (5-gallon ≈ 19 L minimum); consistent soil moisture critical for fruit set; vulnerable to blossom-end rot.","url":"https://www.almanac.com/plant/bell-peppers","field":"lightProfile,containerProfile,wateringProfile"},{"citation":"Confidence note — wateringProfile.baseIntervalDays (3 days) and hotWeatherMultiplier (2): authoritative sources specify outcome (even moisture, ~1 in/week soaking, daily in hot weather for containers) rather than a fixed day interval. The 3-day base is a conservative interpretation of ''soak at least weekly'' plus ''do not let soil dry between waterings'' for typical conditions; multiplier reflects RHS ''may need daily watering in hot, dry weather''. feedingProfile.baseIntervalDays (21) maps Clemson''s 3-4 week side-dress cadence to a conservative 21 days.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('cucumis-sativus', 'Cucumis sativus', array['Cucumber','Garden cucumber']::text[], 'vegetable', 'vine', true, false, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"containerLeachAdjustment":0.5,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-drained","sandy-loam","compost-enriched","ph-6.0-6.5"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":14}'::jsonb, '{"coldHardyMinC":10,"heatStressC":35,"frostSensitive":true}'::jsonb, '{"productiveMonths":[7,8,9]}'::jsonb, array['Frost-tender: plants are killed by light frost; do not plant outdoors until soil reaches 21C (70F) at 1-inch depth.','Standard varieties need insect (bee) pollination for fruit set; poor pollination causes misshapen or dropped fruit. Parthenocarpic hybrids set fruit without pollinators.','Heavy feeder for water: needs ~1 inch (25mm) of water per week; uneven moisture causes bitter or misshapen fruit.','Pests: striped/spotted cucumber beetles, aphids, spider mites, pickleworms, squash vine borers.','Diseases: powdery and downy mildew, bacterial wilt (vectored by cucumber beetles), anthracnose, angular leaf spot, mosaic viruses.','Best grown on a 3-6 ft trellis; container minimum is a 5-gallon (19L) pot with 1-2 plants and a support.']::text[], 0.95, '[{"citation":"University of Minnesota Extension — Growing cucumbers in home gardens: ~1 inch of water per week; sow when soil is at least 70F at 1-inch depth; plants cannot survive freezing; thin to 8-12 inches apart; use a 3-to-4-foot trellis; soil pH 6.0-6.5.","url":"https://extension.umn.edu/vegetables/growing-cucumbers","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing cucumbers in home gardens: frost-tender (plants cannot survive freezing temperatures), plant after last frost; soil pH 6.0-6.5; recommends a 3-4 ft trellis.","url":"https://extension.umn.edu/vegetables/growing-cucumbers","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC — Cucumber: best growth between 75 and 85F; minimum planting soil temp 70F, no germination below 50F; very tender, killed by light frosts; harvest about 50-70 days; pre-plant 5-10-10 fertilizer, sidedress nitrogen; trellis about 6 feet high; most varieties require pollinating insects, parthenocarpic hybrids do not.","url":"https://hgic.clemson.edu/factsheet/cucumber/","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC — Cucumber: pre-plant fertilizer 5-10-10 at 3 lb per 100 sq ft, then sidedress nitrogen before vine development; soil pH 6.0-6.5.","url":"https://hgic.clemson.edu/factsheet/cucumber/","field":"feedingProfile"},{"citation":"The Old Farmer''s Almanac — Growing Cucumbers in Pots, Containers, Bags: at least a 5-gallon (about 19L) container, minimum 12 inches wide and 12 inches deep, 1-2 plants per pot; fresh potting/soilless mix; trellis recommended.","url":"https://www.almanac.com/growing-cucumbers-pots","field":"containerProfile"},{"citation":"University of Illinois Extension / UGA Extension — cucumbers require long warm days and plenty of sunshine (full sun). Extensions describe the requirement as ''full sun'' rather than a precise hours figure; targetSunHours 8 and minSunHours 6 reflect the standard full-sun definition (6+ hours/day).","url":"https://extension.illinois.edu/gardening/cucumber","field":"lightProfile"},{"citation":"Confidence note — lightProfile (targetSunHours/min/maxSunHours): authoritative extensions specify ''full sun'' / ''plenty of sunshine'' for cucumber but do not state an exact hours-per-day number. Values are conservative estimates derived from the standard horticultural definition of full sun (6+ hours direct sun); target 8h, max 14h reflect summer daylength, not a cited cap.","field":"confidence"},{"citation":"Confidence note — wateringProfile.baseIntervalDays and hotWeatherMultiplier: extensions specify ~1 inch (25mm) of water per week and warn cucumbers are heavy water users with low drought tolerance, but do not give a fixed day interval. A 2-day base interval (and 1.5x in hot weather) is a conservative conversion of ''consistent, uniform moisture, ~1 inch/week, more in heat'' for a container/raised-bed care schedule.","field":"confidence"},{"citation":"Confidence note — feedingProfile intervals: extensions describe pre-plant fertilizer plus nitrogen sidedressing ''when plants begin to vine'' / about one week after bloom then ~3 weeks later, not a fixed recurring day interval. A 14-day base/fruiting interval is a conservative schedule consistent with that cadence; preferredNpk 5-10-10 follows the Clemson pre-plant recommendation (avoid excess nitrogen, which reduces fruiting).","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('cucurbita-pepo', 'Cucurbita pepo', array['Zucchini','Summer Squash','Courgette']::text[], 'vegetable', 'bush', false, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"containerLeachAdjustment":0.7,"preferredNpk":"balanced (e.g. 10-10-10), side-dress when vines spread / female flowers appear"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":38,"idealMaxLiters":57,"soilMixTags":["rich","compost-amended","well-draining","ph-6.0-6.5"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":10,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"productiveMonths":[7,8,9],"dormancyMonths":[11,12,1,2]}'::jsonb, array['Heavy water feeder: needs at least ~25mm (1 inch) water per week; soil dries faster in containers, so container plants may need daily watering in hot weather.','Very frost-sensitive warm-season annual: do not plant out until after last frost and soil is at least ~18C (65-70F) at seed depth.','Susceptible to squash vine borer, squash bug, and striped/spotted cucumber beetles.','Prone to powdery mildew and cucurbit viruses; keep foliage dry by watering at the base (drip/soaker), not overhead.','Poor fruit set often reflects a pollination problem (low pollinator activity), not a watering or feeding fault; early flowers are male only.','Container minimum of ~19L (5 gal) is the practical floor; a 38-57L (10-15 gal) container gives far better yield and far less watering stress.']::text[], 0.2, '[{"citation":"University of Minnesota Extension — Growing summer squash and zucchini in home gardens. Sow after last frost once soil is at least 70F at 2-inch depth (late May-early June in MN); vine crops need about one inch of water per week; keep foliage dry with drip/soaker hoses; side-dress when vines begin spreading (e.g. 1 cup 27-3-3 per 100 ft of row); best soil pH 6.0-6.5; pests include cucumber beetles, squash vine borer, squash bugs; diseases include powdery mildew and cucurbit viruses.","url":"https://extension.umn.edu/vegetables/growing-summer-squash-and-zucchini","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing summer squash and zucchini in home gardens. Slightly acidic best soil pH 6.0-6.5; side-dress fertilizer when vines begin spreading; soil test before planting (medium nutrient requirement).","url":"https://extension.umn.edu/vegetables/growing-summer-squash-and-zucchini","field":"feedingProfile"},{"citation":"University of Maryland Extension — Growing Summer Squash (Zucchini) in a Home Garden. Full sun requires direct light at least 6 hours/day; prefers 8-10 hours/day. Water deeply and regularly at the base, especially in hot dry weather and once fruits form. Medium nutrient requirement; incorporate compost/fertilizer before planting, then side-dress when female flowers appear. Very tender warm-season annual; frost will injure top growth. Days to maturity 50-65 from transplant. Spacing: bush types ~2-3 ft.","url":"https://extension.umd.edu/resource/growing-summer-squash-zucchini-home-garden","field":"lightProfile"},{"citation":"University of Maryland Extension — Growing Summer Squash (Zucchini) in a Home Garden. Very tender warm-season annual; frost will injure top growth; needs warm weather to grow. Pests/diseases: bacterial wilt, cucumber beetle, squash bug, squash vine borer, powdery mildew, downy mildew, pollination problems.","url":"https://extension.umd.edu/resource/growing-summer-squash-zucchini-home-garden","field":"temperatureProfile"},{"citation":"The Old Farmer''s Almanac — Growing Zucchini: How to Plant, Grow, and Harvest. Direct sow ~2 weeks after last frost when soil is around 65-70F; needs 6 to 8 hours of direct sun daily; needs at least an inch of water each week; slightly acidic to neutral pH ~5.8-7.0; most varieties average ~60 days to maturity; harvest fruit at 6-8 inches.","url":"https://www.almanac.com/plant/zucchini","field":"seasonality"},{"citation":"Container sizing for zucchini is not given a single authoritative number by US extension services; the schema requires a container minimum. Synthesis of horticultural guidance places the practical floor near 5 gal (~19L) with 10-15 gal (~38-57L) markedly better given zucchini''s large root system and high water demand. recommendedMinLiters, idealMinLiters, and idealMaxLiters are conservative estimates, not directly extension-sourced.","field":"confidence"},{"citation":"Estimated thermal thresholds: coldHardyMinC (~10C) reflects that zucchini is a very tender warm-season crop needing soil at least ~18C (65-70F) to germinate and warm air to grow (UMN, UMD, Almanac); heatStressC (~32C) reflects typical cucurbit heat/pollination stress. Exact stress temperatures are not published per-degree by these sources and are conservative estimates.","field":"temperatureProfile"}]'::jsonb, 1, '2026-06-02'),
  ('daucus-carota', 'Daucus carota sativus', array['Carrot','Garden carrot']::text[], 'root', 'rosette', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"containerLeachAdjustment":0.75,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":7.5,"idealMinLiters":11,"idealMaxLiters":19,"soilMixTags":["free-draining","sandy-loam","stone-free","low-nitrogen","loose"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-4,"heatStressC":24,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"us-cold-zone4":[{"startMonth":4,"endMonth":7}],"uk-rhs":[{"startMonth":4,"endMonth":7}],"us-southeast-zone8":[{"startMonth":2,"endMonth":3},{"startMonth":7,"endMonth":8}]},"productiveMonths":[6,7,8,9,10,11],"dormancyMonths":[]}'::jsonb, array['Slow to germinate (up to ~3 weeks); keep the seedbed consistently moist until emergence.','Forking and misshapen roots from stony, cloddy, or heavy clay soil, or from soil drying out; use loose, stone-free, free-draining soil.','Excess nitrogen causes forked/hairy roots and lush tops at the expense of the root; use a low-nitrogen feed (e.g. 5-10-10) and avoid high-N fertilizer.','Bitter, tough, undersized roots when underwatered during dry spells; aim for about 1 inch (25 mm) of water per week.','Poor germination and weak growth in hot weather; seeds will not germinate above ~95F (35C) and plants grow poorly in heat.','Container depth matters: baby/round varieties suit pots 6-8 in (15-20 cm) deep, while full-length varieties need 12+ in (30+ cm) deep containers or should be harvested young.','Roots tolerate light frost (flavor sweetens after frost) but heavy freezing damages tops; mulch with straw to overwinter in the ground.']::text[], 0, '[{"citation":"UMN Extension — Growing carrots and parsnips in home gardens: light sandy loam soil, pH 6-7; thin to 2-4 in apart; water deeply once a week on heavier soils, twice a week on sandier soils, at least 1 inch of water per week; seeds can take up to three weeks to germinate; Minnesota planting starts about April 15; avoid weed-and-feed fertilizers.","url":"https://extension.umn.edu/vegetables/growing-carrots-and-parsnips","field":"wateringProfile"},{"citation":"UMN Extension — Growing carrots and parsnips: spacing, soil pH 6-7, and ~April-onward planting window used for seasonality (cold-zone) and soil mix tags.","url":"https://extension.umn.edu/vegetables/growing-carrots-and-parsnips","field":"seasonality"},{"citation":"Clemson HGIC — Carrot, Beet, Radish & Parsnip: soil germination temperature 55-75F (seeds will not germinate above 95F); harvest about 65-75 days after planting; rows 12-18 in apart, thin to 2-3 in between plants; pre-plant 5-10-10 fertilizer, sidedress with calcium nitrate / 34-0-0; loamy or sandy stone-free soil, pH 6.0-6.5; SC planting dates Feb-Mar spring and Jul-Aug fall.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"temperatureProfile"},{"citation":"Clemson HGIC — Carrot, Beet, Radish & Parsnip: pre-plant 5-10-10 fertilizer and sidedressing schedule; basis for preferredNpk and SC fall/spring planting windows.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"feedingProfile"},{"citation":"RHS — How to grow Carrots: drought resistant, seldom need watering but benefit from a good soaking every fortnight in long dry spells; container-grown carrots need regular watering as pots dry faster; main sow Apr to early July (Feb-Mar under cloches/fleece); baby carrots in 4-6 weeks, full-size about 90 days (12-16 weeks); grow well in containers with peat-free multipurpose compost, long-rooted types need deep containers; can stay in the ground over winter with straw/cardboard frost protection.","url":"https://www.rhs.org.uk/vegetables/carrots/grow-your-own","field":"wateringProfile"},{"citation":"RHS — How to grow Carrots: container growing guidance (deep containers for long-rooted types, multipurpose compost, sow thinly under ~1 cm) and overwintering/frost tolerance used for containerProfile and frost notes.","url":"https://www.rhs.org.uk/vegetables/carrots/grow-your-own","field":"containerProfile"},{"citation":"Old Farmer''s Almanac — Carrots: full sun, direct light at least 6 hours/day (prefers 8-10 hours); carrots are semi-hardy and withstand light frosts (flavor improves after frost) but not hard freezes, roots tolerate colder than tops; germinate best 55-65F, not exceeding 75F, will not germinate above 95F; baby/dwarf carrots need 6-8 in deep containers, standard carrots at least 12 in deep; a 1-gallon pot (6-7 in diameter, 12-18 in deep) holds 3-4 plants; apply low-nitrogen fertilizer every 3-4 weeks (excess nitrogen harms root development); keep soil moist as dry soil causes forking.","url":"https://www.almanac.com/plant/carrots","field":"lightProfile"},{"citation":"Old Farmer''s Almanac — Carrots: low-nitrogen fertilizer every 3-4 weeks for container carrots (basis for feeding interval of 21 days and low-nitrogen NPK preference) and container depth/size in gallons.","url":"https://www.almanac.com/plant/carrots","field":"feedingProfile"},{"citation":"Old Farmer''s Almanac — Carrots: container depth (6-8 in baby, 12+ in standard) and 1-gallon (~3.8 L) pot for 3-4 plants; basis for recommendedMinLiters/idealMinLiters/idealMaxLiters for a small home container of carrots.","url":"https://www.almanac.com/plant/carrots","field":"containerProfile"},{"citation":"Confidence note: baseIntervalDays (3 days) is an estimate. Sources give weekly volume (~1 inch/week, once on heavy soil and twice on sandy soil per UMN; soaking every fortnight in dry spells per RHS; keep container soil moist per Almanac) rather than an explicit fixed-day interval. A 3-day interval is a conservative midpoint for keeping the seedbed and container moist; hotWeatherMultiplier<1 and dryingTolerance=medium reflect the drought-resistant-but-forks-when-dry guidance.","url":"https://extension.umn.edu/vegetables/growing-carrots-and-parsnips","field":"confidence"},{"citation":"Confidence note: coldHardyMinC (-4C) and heatStressC (24C) are conservative estimates derived from qualitative guidance (semi-hardy, withstands light frost but not hard freeze; germinates best 55-65F and grows poorly in heat / will not germinate above 95F). No source gave an exact lethal-low or heat-stress temperature in Celsius for carrots.","url":"https://www.almanac.com/plant/carrots","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('lactuca-sativa', 'Lactuca sativa', array['Lettuce','Garden lettuce']::text[], 'vegetable', 'rosette', false, null, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":0.6,"rainSkipThresholdMm":10}'::jsonb, '{"baseIntervalDays":14,"postHarvestIntervalDays":30,"containerLeachAdjustment":0.7,"preferredNpk":"high-nitrogen (e.g. 10-10-10 base with nitrogen side-dress such as 15-0-0)"}'::jsonb, '{"recommendedMinLiters":6,"idealMinLiters":10,"idealMaxLiters":40,"soilMixTags":["potting-mix","well-draining","rich-organic-matter","moisture-retentive","slightly-acidic-ph-6.0-6.5"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-2,"heatStressC":24,"frostSensitive":false}'::jsonb, '{"productiveMonths":[3,4,5,6,9,10,11]}'::jsonb, array['Bolting (premature seed-stalk formation) and bitter flavor when temperatures exceed about 24 C / 75 F or under long, hot, high-light days.','Shallow roots dry out quickly in containers; keep soil evenly moist and water more often than in-ground plantings (every 4-5 days, more in heat).','Pests: aphids, cabbage looper, corn earworm, leafhoppers, slugs and snails, cutworms, flea beetles.','Diseases: gray mold (Botrytis), Rhizoctonia bottom rot, Sclerotinia drop, aster yellows (spread by leafhoppers).','Tolerates light frost (to roughly -2 C / 28 F with cover) but freezing temperatures stop growth; protect with row cover in cold snaps.']::text[], 0.6, '[{"citation":"UMN Extension - Growing lettuce, endive and radicchio in home gardens. Optimal night low 50 F / day high 68 F; freezing stops growth; ~1 inch rainfall per week; 10-10-10 at planting plus nitrogen side-dress at 4 in tall; bolting when temps exceed ~75 F; pests include cutworms, slugs, flea beetles, aster yellows.","url":"https://extension.umn.edu/vegetables/growing-lettuce-endive-and-radicchio","field":"temperatureProfile"},{"citation":"UMN Extension - Growing lettuce, endive and radicchio in home gardens. Spring planting in April when soil workable; fall ~3 months before first frost; productive cool-season window.","url":"https://extension.umn.edu/vegetables/growing-lettuce-endive-and-radicchio","field":"seasonality"},{"citation":"UMN Extension - Growing lettuce, endive and radicchio in home gardens. ~1 inch rainfall per week adequate; sandy soils need more frequent watering; water before harvest for crispness.","url":"https://extension.umn.edu/vegetables/growing-lettuce-endive-and-radicchio","field":"wateringProfile"},{"citation":"Clemson HGIC - Lettuce. Optimum growth 55-65 F; germination 60-80 F; light frost tolerated, ~4 degrees frost protection down to 28 F under cover; bolting/bitterness above 75 F; pre-plant 5-10-10 plus calcium-nitrate side-dress.","url":"https://hgic.clemson.edu/factsheet/lettuce/","field":"temperatureProfile"},{"citation":"Clemson HGIC - Lettuce. Maintain uniform moisture, moisten soil to 6 inches deep; pests aphids, cabbage looper, corn earworm, leafhoppers, slugs, snails; diseases gray mold, Rhizoctonia bottom rot, Sclerotinia drop.","url":"https://hgic.clemson.edu/factsheet/lettuce/","field":"commonIssues"},{"citation":"UGA Extension - Growing Lettuce in Your Garden. At least 8-10 hours of sunlight per day; slightly acidic soil pH 6.0-6.5; transplants 10-12 in apart.","url":"https://site.extension.uga.edu/laurensgarden/2021/09/growing-lettuce-in-your-garden/","field":"lightProfile"},{"citation":"UGA Extension - Growing Lettuce in Your Garden. Irrigate every 4-5 days as needed; container/raised-bed lettuce needs more frequent irrigation.","url":"https://site.extension.uga.edu/laurensgarden/2021/09/growing-lettuce-in-your-garden/","field":"wateringProfile"},{"citation":"UGA Extension - Growing Lettuce in Your Garden. 5-10-10 at planting, then ~2 lb of 5-10-15 per 100 sq ft each month during the growing season (monthly feeding cadence).","url":"https://site.extension.uga.edu/laurensgarden/2021/09/growing-lettuce-in-your-garden/","field":"feedingProfile"},{"citation":"UC ANR Master Gardeners (Under the Solano Sun) - Growing Lettuce in Containers. Container depth 6-9 inches suits shallow-rooted lettuce; bigger container gives more options; potting mix ~70-80% peat/coir, 20-30% perlite/bark, with dolomitic lime; high-nitrogen slow-release at planting plus liquid feed; full sun in spring, afternoon shade in heat.","url":"https://ucanr.edu/blog/under-solano-sun/article/growing-lettuce-containers","field":"containerProfile"},{"citation":"Confidence note: Container volume in liters is estimated. Sources give container depth (UC ANR: 6-9 in) and per-plant footprint (an 8-inch / 18-inch pot per the search summary) rather than a liter figure; recommendedMinLiters 6 (single plant), idealMin 10, idealMax 40 are conservative conversions from those dimensions. wateringProfile baseIntervalDays 2 is tuned for shallow-rooted container culture (sources state ''every 4-5 days'' in-ground and ''more frequent'' in containers); hotWeatherMultiplier 0.6 and rainSkipThresholdMm 10 are app-tuning estimates derived from the ~1 in/week guidance. verticalSuitability 0.6 reflects suitability for shallow raised beds/window boxes, not a sourced rating.","url":"https://ucanr.edu/blog/under-solano-sun/article/growing-lettuce-containers","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('phaseolus-vulgaris', 'Phaseolus vulgaris', array['Green bean','Snap bean','French bean','String bean','Bush bean']::text[], 'vegetable', 'bush', false, true, 0, '{"baseIntervalDays":3,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":30,"containerLeachAdjustment":0.5,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":8,"idealMinLiters":19,"idealMaxLiters":38,"soilMixTags":["well-drained","fertile","potting-mix-plus-compost","ph-6-to-7"]}'::jsonb, '{"targetSunHours":7,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":4,"heatStressC":29,"frostSensitive":true}'::jsonb, '{"productiveMonths":[7,8,9],"dormancyMonths":[11,12,1,2,3]}'::jsonb, array['Frost-sensitive annual: plants are killed by even a light frost, so sow only after the last frost and once soil is at least 16 C (60 F) at 10 cm depth (Clemson HGIC).','Direct-sow rather than transplant; beans resent root disturbance (Old Farmer''s Almanac, UMN Extension).','Avoid high-nitrogen feed: too much nitrogen produces lush foliage and few pods. Beans fix their own nitrogen and have low fertilizer needs (UMN Extension, Old Farmer''s Almanac).','Most critical watering period is during flowering, pod set, and pod development; drought stress then sharply reduces yield (Clemson HGIC, UMN Extension).','Container minimum (8 L) is sized for ONE bush plant; a 19 L (5-gallon) pot holds about three bush plants (Old Farmer''s Almanac).','POLE/climbing varieties of the same species are NOT covered by the bush defaults here: they reach ~2 m, require a sturdy 1.8-2.4 m (6-8 ft) trellis or wigwam, and need a larger container (RHS: min ~75 cm wide x 45 cm deep). For pole beans set requiresSupport=true and use a larger pot.']::text[], 0.3, '[{"citation":"University of Minnesota Extension - Growing beans in home gardens. Bush beans grow ~2 ft tall and do not need support; pole beans need a trellis and can reach 6 ft. One inch of rainfall per week; an inch of water wets sandy soil to ~10 in and clay to ~6 in. Beans need less fertilizer than other crops; prefers pH 6-7. Plant after soil warms (late May / early June in MN).","url":"https://extension.umn.edu/vegetables/growing-beans","field":"wateringProfile"},{"citation":"University of Minnesota Extension - Growing beans in home gardens. Bush beans do not need support (requiresSupport=false); seeds spaced ~4 in apart, rows 2-3 ft apart. Beans require less fertilizer than most crops (low feeding need).","url":"https://extension.umn.edu/vegetables/growing-beans","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC 1308 - Bush & Pole-Type Snap Beans. Snap beans grow best at average temperatures of 60-75 F; do not plant until soil is at least 60 F at 4-in depth; plants are killed by light frost (frostSensitive). Maturity ~55 days. Pre-plant fertilizer 5-10-10; sidedress nitrogen before first bloom. Water to moisten soil to 6-in depth; critical moisture period is pod set and pod development.","url":"https://hgic.clemson.edu/factsheet/bush-pole-type-snap-beans/","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC 1308 - Bush & Pole-Type Snap Beans. Recommended fertilizer 5-10-10 pre-plant with a nitrogen sidedress before first bloom; supports the low-nitrogen, ~30-day feeding cadence.","url":"https://hgic.clemson.edu/factsheet/bush-pole-type-snap-beans/","field":"feedingProfile"},{"citation":"The Old Farmer''s Almanac - How to Grow Green Beans. Beans need full sun; container guidance ~6-8 hours of sun per day. An 8-in deep x 8-in wide container holds one bush plant; a 5-gallon (~19 L) pot holds up to three bush or pole plants. Use a low-nitrogen 5-10-10 to avoid excess foliage. Direct-sow after frost into warm (55 F+) soil.","url":"https://www.almanac.com/plant/beans","field":"containerProfile"},{"citation":"The Old Farmer''s Almanac - How to Grow Green Beans. Full sun; container beans want roughly 6-8 hours of direct sun per day (vegetables grown for pods perform best with 8+ hours).","url":"https://www.almanac.com/plant/beans","field":"lightProfile"},{"citation":"Royal Horticultural Society - How to grow French beans. Highly frost-sensitive; sow outdoors only after the last frost. Dwarf (bush) varieties ~45 cm tall need only twiggy support; climbing varieties ~2 m need tall canes/wigwams. Dwarf-bean container min ~30-45 cm wide; climbing-bean container min ~75 cm wide x 45 cm deep. Water during dry weather, especially once flowering and forming pods.","url":"https://www.rhs.org.uk/vegetables/french-beans/grow-your-own","field":"containerProfile"},{"citation":"Confidence note: heatStressC (29 C / ~85 F) is a conservative estimate derived from Clemson''s stated optimal range of 60-75 F (above which bean blossoms commonly drop) rather than a single published heat-stress threshold. coldHardyMinC (4 C) is likewise conservative: sources state plants are killed by light frost, so the safe lower bound is set above freezing rather than at an exact published figure. hotWeatherMultiplier (1.5) and rainSkipThresholdMm (25 mm = the cited 1 in/week) are derived operational defaults, not directly published intervals.","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('pisum-sativum', 'Pisum sativum', array['Pea','Garden pea','Green pea','English pea']::text[], 'vegetable', 'climbing', true, true, 0, '{"baseIntervalDays":4,"dryingTolerance":"medium","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":12}'::jsonb, '{"baseIntervalDays":14,"fruitingIntervalDays":14,"containerLeachAdjustment":0.75,"preferredNpk":"5-10-10"}'::jsonb, '{"recommendedMinLiters":35,"idealMinLiters":35,"idealMaxLiters":60,"soilMixTags":["well-drained","multi-purpose-compost","neutral-ph"]}'::jsonb, '{"targetSunHours":6,"minSunHours":6,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-4,"heatStressC":29,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"default":[{"startMonth":3,"endMonth":6}],"coastal-warm":[{"startMonth":2,"endMonth":3}]},"productiveMonths":[5,6,7],"dormancyMonths":[11,12,1]}'::jsonb, array['Heat sensitive: stops flowering and setting pods once temperatures exceed about 29C (85F); grow as a cool-season crop in spring or fall.','Young plants tolerate light frost, but open blossoms can be damaged by freezing temperatures.','Powdery mildew, white mold, and Fusarium wilt; water at the soil line and avoid wetting foliage.','Pests: aphids, cutworms, pea/bean weevils, pea moth, slugs, and snails.','Avoid excess nitrogen; peas fix their own and high N reduces pod production.','Tall varieties climb by tendrils to about 1.5-1.8m and require netting, trellis, or pea sticks installed at sowing.','Container minimum of 35L reflects RHS guidance (about a 45cm-wide pot) for dwarf and mangetout types; container plants dry quickly and yield less than in-ground.']::text[], 0.9, '[{"citation":"University of Minnesota Extension, Growing peas in home gardens: full sun; ideal growing temperature 55-65F (13-18C); growth/flowering stops above 85F (29C); soak soil to at least 1 inch per week during the growing season; peas need less fertilizer than other crops (low-phosphorus blends); soil pH 6-7.5; about 60 days to maturity; tall varieties to 5 ft need trellises; problems include cutworms, aphids, powdery mildew, white mold.","url":"https://extension.umn.edu/vegetables/growing-peas","field":"wateringProfile"},{"citation":"University of Minnesota Extension, Growing peas in home gardens: ideal growing temperature 55-65F (13-18C); plants stop growing/flowering above 85F (29C); young plants survive light frost.","url":"https://extension.umn.edu/vegetables/growing-peas","field":"temperatureProfile"},{"citation":"University of Minnesota Extension, Growing peas in home gardens: peas need less fertilizer than other crops; low-phosphorus blends suggested by soil test.","url":"https://extension.umn.edu/vegetables/growing-peas","field":"lightProfile"},{"citation":"Royal Horticultural Society (RHS), Peas / grow your own: sow outdoors March-June once soil reaches 10C (50F); minimum container pot size 45cm wide for dwarf/mangetout types; container peas need regular watering as compost dries rapidly; feed container peas with a high-potassium liquid feed (e.g. tomato feed) once a fortnight from flowering; tall varieties up to 1.8m need netting/canes; water well at flowering and again two weeks later.","url":"https://www.rhs.org.uk/vegetables/peas/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS), Peas / grow your own: feed container-grown peas with a high-potassium organic liquid fertiliser (e.g. tomato feed) once a fortnight (every 14 days) from when flowers appear; in-ground peas generally need no feeding.","url":"https://www.rhs.org.uk/vegetables/peas/grow-your-own","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC, Garden Peas: full sun for maximum flavor and sugar; cool-season crop that suffers in summer heat; frost-tolerant foliage but blossoms cannot withstand freezing; ideal pH 6.0-6.5; 5-10-10 fertilizer at 3 lb per 100 sq ft if no soil test; avoid excess nitrogen; early varieties 55-64 days; support with netting, trellis, wires, or pea brush erected at planting; powdery mildew, Fusarium wilt, aphids.","url":"https://hgic.clemson.edu/factsheet/garden-peas/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC, Garden Peas: full sun required; spring planting windows by region (Piedmont Mar 1-Apr 5; Coastal Feb 1-Mar 15).","url":"https://hgic.clemson.edu/factsheet/garden-peas/","field":"seasonality"},{"citation":"Clemson Cooperative Extension HGIC, Garden Peas: support peas with netting, trellis, wires, or pea brush; peas climb by tendrils. RHS notes tall varieties reach about 1.8m. Supports high vertical/trellis suitability.","url":"https://hgic.clemson.edu/factsheet/garden-peas/","field":"verticalSuitability"},{"citation":"Confidence note: schema requires Celsius numerics not stated verbatim by sources. heatStressC=29 converts UMN/Clemson''s 85F threshold. coldHardyMinC=-4 is a conservative estimate of ''light frost'' tolerance for young foliage (sources state young plants survive light frost and blossoms are frost-damaged, without a numeric low). frostSensitive=false reflects the foliage''s cool-season hardiness, but blossoms are frost-sensitive (captured in commonIssues). Watering baseIntervalDays=4 and hotWeatherMultiplier estimate from UMN''s ''1 inch per week, soak soil'' plus RHS container ''dries rapidly''; rainSkipThresholdMm=12 (~0.5in) is a conservative care-engine default. recommendedMinLiters=35 converts RHS ''45cm-wide pot''; idealMaxLiters=60 is an estimate for larger/taller varieties.","url":"https://extension.umn.edu/vegetables/growing-peas","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('raphanus-sativus', 'Raphanus sativus', array['Radish','Garden radish','Common radish']::text[], 'vegetable', 'rosette', false, null, 0, '{"baseIntervalDays":3,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"preferredNpk":"5-10-10","containerLeachAdjustment":0.75}'::jsonb, '{"recommendedMinLiters":8,"idealMinLiters":12,"idealMaxLiters":28,"soilMixTags":["well-drained","loose","sandy-loam","multipurpose-compost"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":-2,"heatStressC":24,"frostSensitive":false}'::jsonb, '{"productiveMonths":[4,5,6,9,10],"plantingWindowsByZone":{"4":[{"startMonth":4,"endMonth":5},{"startMonth":8,"endMonth":9}]}}'::jsonb, array['Inconsistent moisture causes pithy, woody, or pungent, split roots; keep soil evenly moist (UMN, Cornell).','Bolting (going to seed) and strong flavor occur in heat; radish is a cool-season crop best in spring and fall (RHS, Clemson).','Roots fail to swell if sown too thickly or shaded; thin garden radishes to about 2 in (5 cm) apart (UMN, RHS).','Germination fails when soil is above ~35 C (95 F); optimum soil temperature is 45-85 F / 7-29 C (Clemson).','Common pests: flea beetles, cabbage maggots/cabbage root fly, aphids, wireworms; diseases include clubroot, black rot, Alternaria (UMN).','Container note: short-rooted salad radishes grow well in pots at least 30 cm (1 ft) wide and deep, or a 2-gallon (~8 L) pot for 5-6 plants; long winter/daikon types need 30 cm-plus soil depth and a larger container (RHS, Old Farmer''s Almanac).']::text[], 0.1, '[{"citation":"University of Minnesota Extension — Growing radishes in home gardens (watering ~1 in/week, keep evenly moist; planting depth 1/4-1 in; spacing ~2 in for garden radishes, 4-6 in for daikon; maturity 3-5 weeks; cool/cold tolerant; pests: flea beetles, cabbage maggots, wireworms; diseases: Alternaria, black rot, clubroot).","url":"https://extension.umn.edu/vegetables/growing-radishes","field":"wateringProfile"},{"citation":"University of Minnesota Extension — Growing radishes in home gardens (spacing, maturity 3-5 weeks, seasonality spring early April-early May and fall Aug 1-Sep 1, cold tolerance, common pests/diseases).","url":"https://extension.umn.edu/vegetables/growing-radishes","field":"commonIssues"},{"citation":"Clemson Cooperative Extension HGIC — Carrot, Beet, Radish & Parsnip (optimum soil temperature for germination 45-85 F = 7-29 C; optimum growing temperature 50-65 F = 10-18 C; will not germinate above 95 F = 35 C; maturity 21-30 days; planting 1/2 in deep, thin to 2-3 in; pre-plant 5-10-10 fertilizer; sandy/sandy-loam soils best; water to moisten to 6 in depth).","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC — Carrot, Beet, Radish & Parsnip (recommends 5-10-10 fertilizer pre-plant for root crops; sidedress when plants reach 4 in; vegetables do best with full sunlight, at least 4-6 hours a day).","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"feedingProfile"},{"citation":"Clemson Cooperative Extension HGIC — vegetables do best in full sunlight, at least 4 to 6 hours per day; radish prefers cool, moist conditions.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"lightProfile"},{"citation":"Royal Horticultural Society (RHS) — How to grow radishes (open, sunny site; light shade acceptable for salad radishes in midsummer; keep soil consistently moist; salad sowing 1 cm/0.5 in deep, 2.5-5 cm apart, 15 cm between rows; containers at least 30 cm/1 ft wide and deep in multipurpose compost; salad radishes ready in ~4 weeks, winter/Oriental at least 8 weeks; cool-season, bolts in heat).","url":"https://www.rhs.org.uk/vegetables/radishes/grow-your-own","field":"containerProfile"},{"citation":"Royal Horticultural Society (RHS) — How to grow radishes (sunny/open site, light shade acceptable; cool-season crop bolting in excessive heat).","url":"https://www.rhs.org.uk/vegetables/radishes/grow-your-own","field":"lightProfile"},{"citation":"The Old Farmer''s Almanac — Radishes: Planting, Growing, and Harvesting; Vegetable Container Size Chart (radishes recommend a 2-gallon pot, ~8 in/20-23 cm diameter, 6-8 in/15-20 cm deep, for 5-6 plants; direct-sow about 1/2 in deep; cool-season crop tolerant of cold).","url":"https://www.almanac.com/plant/radishes","field":"containerProfile"},{"citation":"Confidence note — Light tolerance bounds (maxSunHours 10) and exact watering interval (baseIntervalDays 3) are conservative app-engine estimates derived from qualitative source guidance: sources specify ''at least 4-6 hours'' full sun and ''~1 inch of water per week / keep consistently moist'' rather than a hard upper sun bound or a fixed day interval. coldHardyMinC (-2 C) reflects ''tolerant of cold/light frost'' without a published exact lethal minimum; heatStressC (24 C) is derived from the stated 50-65 F optimum growing range and bolting-in-heat warnings, not a single published threshold.","url":"https://hgic.clemson.edu/factsheet/carrot-beet-radish-parsnip/","field":"confidence"}]'::jsonb, 1, '2026-06-02'),
  ('solanum-lycopersicum', 'Solanum lycopersicum', array['Tomato','Garden tomato']::text[], 'vegetable', 'vine', true, true, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":2,"rainSkipThresholdMm":13}'::jsonb, '{"baseIntervalDays":7,"fruitingIntervalDays":5,"postHarvestIntervalDays":14,"preferredNpk":"low-N / high-K once fruiting (e.g. 8-32-16 to start, high-potassium tomato feed when fruits swell)"}'::jsonb, '{"recommendedMinLiters":19,"idealMinLiters":19,"idealMaxLiters":40,"soilMixTags":["well-draining","rich-compost","container-potting-mix"]}'::jsonb, '{"targetSunHours":8,"minSunHours":6,"maxSunHours":10}'::jsonb, '{"coldHardyMinC":13,"heatStressC":32,"frostSensitive":true}'::jsonb, '{"plantingWindowsByZone":{"us-cold-zone3-5":[{"startMonth":5,"endMonth":6}],"us-warm-zone6-8":[{"startMonth":4,"endMonth":5}]},"productiveMonths":[7,8,9,10],"dormancyMonths":[11,12,1,2,3]}'::jsonb, array['Blossom-end rot from inconsistent watering and calcium uptake; keep soil evenly moist','Fruit cracking/splitting from soil-moisture fluctuations','Flower drop when night temperatures fall below ~13C (55F) or fruit set fails above ~32-35C (90F)','Early blight, Septoria leaf spot and late blight in wet conditions','Top-heavy plants blow over in undersized containers; stake or cage at planting','Container plants dry out fast and may need daily watering in peak summer heat']::text[], 0.6, '[{"citation":"Clemson Cooperative Extension HGIC - Tomatoes in Containers (container size 14-20 in / 5-gallon buckets, min 6 h full sun, daily watering in summer, balanced fertilizer weekly, cage/stake cultivars over 2 ft)","url":"https://hgic.clemson.edu/tomatoes-in-containers/","field":"containerProfile"},{"citation":"Clemson Cooperative Extension HGIC - Tomatoes in Containers (minimum 6 hours full sun; daily watering needed in peak summer)","url":"https://hgic.clemson.edu/tomatoes-in-containers/","field":"lightProfile"},{"citation":"University of Minnesota Extension - Growing tomatoes in home gardens (1 inch water per week, soak at base to avoid blossom-end rot; full sun; frost-sensitive, harvest before first frost; stake/cage at planting; fertilize when first fruits enlarge; common issues: blossom-end rot, cracking, sunscald, early blight, Septoria)","url":"https://extension.umn.edu/vegetables/growing-tomatoes","field":"wateringProfile"},{"citation":"University of Minnesota Extension - Growing tomatoes in home gardens (planting after frost danger, mid-April seed start in MN; blossom-end rot, cracking, blights)","url":"https://extension.umn.edu/vegetables/growing-tomatoes","field":"commonIssues"},{"citation":"University of Missouri Extension G6461 - Growing Home Garden Tomatoes (optimal ~75F; growth impaired below 50F, flower drop with night temps below 55F; 1-2 in water/week; low-N high-P medium-high-K starter 8-32-16/6-24-24 then side-dress; support recommended; Missouri planting windows late April-May)","url":"https://extension.missouri.edu/publications/g6461","field":"temperatureProfile"},{"citation":"University of Missouri Extension G6461 - Growing Home Garden Tomatoes (fertilizer low N, high P, med-high K; side-dress when first fruits one-third grown and after first harvest)","url":"https://extension.missouri.edu/publications/g6461","field":"feedingProfile"},{"citation":"University of Missouri Extension G6461 - Growing Home Garden Tomatoes (1 to 2 inches of water per week via rainfall or irrigation)","url":"https://extension.missouri.edu/publications/g6461","field":"wateringProfile"},{"citation":"Royal Horticultural Society - Tomatoes / grow your own (plant out when reliably above 16C/60F; single plant in 30-45cm pot; feed every 10-14 days with high-potassium liquid feed once fruits swell; keep evenly moist to prevent splitting; support cordons; blossom-end rot, splitting, blight)","url":"https://www.rhs.org.uk/vegetables/tomatoes/grow-your-own","field":"feedingProfile"},{"citation":"Royal Horticultural Society - Tomatoes / grow your own (30-45cm / 12-18in pot per single plant; container plants need daily watering in hot weather)","url":"https://www.rhs.org.uk/vegetables/tomatoes/grow-your-own","field":"containerProfile"},{"citation":"The Old Farmer''s Almanac - Growing Tomatoes in Containers (at least 6-8 hours direct sun; surrounding temperature ~70F+; move pots out when night temps reliably above 55F; 5-gal minimum, indeterminate 10+ gal; one plant per container)","url":"https://www.almanac.com/growing-tomatoes-in-containers","field":"lightProfile"},{"citation":"The Old Farmer''s Almanac - Growing Tomatoes in Containers (cherry 2-3 gal, determinate 5 gal minimum, indeterminate 10+ gal; containers at least 12 in deep)","url":"https://www.almanac.com/growing-tomatoes-in-containers","field":"containerProfile"},{"citation":"Estimated values not directly stated by a single source: hotWeatherMultiplier (2x) derived from extension guidance that container tomatoes need daily watering in peak summer vs a ~2-day base interval; rainSkipThresholdMm (~13mm ~= 0.5 in) and overwaterRisk medium (water-loving but rot-prone in poorly drained pots) are conservative app-engine estimates; heatStressC 32C from the ~90F poor-fruit-set threshold; verticalSuitability 0.6 reflects indeterminate vines train well on stakes/trellis but are heavy and not true climbers; postHarvestIntervalDays and containerLeachAdjustment are engine smoothing estimates from extension side-dressing/weekly-feed guidance.","url":"https://hgic.clemson.edu/tomatoes-in-containers/","field":"confidence"}]'::jsonb, 2, '2026-06-02'),
  ('spinacia-oleracea', 'Spinacia oleracea', array['Spinach']::text[], 'vegetable', 'rosette', false, null, 0, '{"baseIntervalDays":2,"dryingTolerance":"low","overwaterRisk":"medium","hotWeatherMultiplier":1.5,"rainSkipThresholdMm":25}'::jsonb, '{"baseIntervalDays":21,"containerLeachAdjustment":0.5,"preferredNpk":"15.5-0-0 (calcium nitrate) or balanced; side-dress 3-4 weeks after planting"}'::jsonb, '{"recommendedMinLiters":10,"idealMinLiters":18,"idealMaxLiters":27,"soilMixTags":["well-drained","high-organic-matter","soilless-potting-mix","ph-6.0-7.0"]}'::jsonb, '{"targetSunHours":6,"minSunHours":4,"maxSunHours":8}'::jsonb, '{"coldHardyMinC":-7,"heatStressC":27,"frostSensitive":false}'::jsonb, '{"plantingWindowsByZone":{"7":[{"startMonth":3,"endMonth":4},{"startMonth":8,"endMonth":9}],"8":[{"startMonth":2,"endMonth":4},{"startMonth":8,"endMonth":10}]},"productiveMonths":[3,4,5,9,10,11],"dormancyMonths":[6,7]}'::jsonb, array['Bolts (sends up seed stalk and turns bitter) when soil dries out or once days warm toward 27C (80F) and daylength lengthens; grow in spring/fall and keep evenly moist.','Heat above 29C (85F) soil inhibits seed germination; optimum germination soil temp is about 21C (70F).','Premature flowering from inconsistent watering, especially in containers which dry quickly and need more frequent watering.','Container minimum (~10 L) reflects spinach''s shallow root system; a wider, shallower pot (at least 30 cm / 1 ft wide and deep per RHS) suits baby-leaf and cut-and-come-again harvests better than a deep narrow one.','Fungal disease and slug/snail pressure increase with overhead/evening watering; water the soil in the morning.']::text[], 0.3, '[{"citation":"Clemson Cooperative Extension HGIC, Spinach factsheet: days to maturity 37-45 days; optimum germination soil temp 70F; >85F inhibits germination; survives 20F without injury; side-dress 1 lb calcium nitrate (15.5-0-0) per 100 sq ft 3-4 weeks after planting; soil pH 6.0-7.0; spring (Mar-Apr Piedmont, Feb-Apr Coastal) and fall (Aug-Oct) planting.","url":"https://hgic.clemson.edu/factsheet/spinach/","field":"temperatureProfile"},{"citation":"Clemson Cooperative Extension HGIC, Spinach factsheet: fertilizer side-dress rate and timing (calcium nitrate 15.5-0-0, 3-4 weeks after planting); soil pH 6.0-7.0; moisten soil to 6 inches; water in morning.","url":"https://hgic.clemson.edu/factsheet/spinach/","field":"feedingProfile"},{"citation":"UMN Extension, Growing spinach and Swiss chard in home gardens: supply about one inch of water (rain) per week; water more frequently on sandy soil; spacing two to four inches apart; sow spring crops until temperatures reach 80F; fall crops sown ~2 months before first frost will not bolt under shortening days.","url":"https://extension.umn.edu/vegetables/growing-spinach-and-swiss-chard","field":"wateringProfile"},{"citation":"Penn State Extension, Growing Spinach (A Cool-Season Vegetable): optimum growing temperature 50-60F; seeds germinate best 45-68F; young seedlings survive as low as 15-20F; full sun but tolerates partial shade; keep soil consistently moist; dry conditions trigger bolting; grows in containers with adequate size and nutrient-rich soilless potting mix.","url":"https://extension.psu.edu/growing-spinach-a-cool-season-vegetable","field":"lightProfile"},{"citation":"Penn State Extension, Growing Spinach: optimum growing temperature 50-60F (~10-16C); young seedlings tolerate 15-20F (~-9 to -7C); spacing four to six inches.","url":"https://extension.psu.edu/growing-spinach-a-cool-season-vegetable","field":"temperatureProfile"},{"citation":"RHS, How to grow spinach: choose a sunny or lightly shaded site; thirsty crop, needs watering in dry weather; plant 15cm (6in) apart, thin to 7.5cm (3in); sow mid-to-late spring and late summer to early autumn; containers at least 30cm (1ft) wide and deep, potting compost dries quickly and needs frequent watering; optimal growth 15-20C (60-70F); baby leaves in ~1 month, mature in ~2 months.","url":"https://www.rhs.org.uk/vegetables/spinach/grow-your-own","field":"containerProfile"},{"citation":"RHS, How to grow spinach: sunny or lightly shaded planting site; partial shade beneficial in warmer months to reduce heat stress and bolting.","url":"https://www.rhs.org.uk/vegetables/spinach/grow-your-own","field":"lightProfile"},{"citation":"The Old Farmer''s Almanac, Spinach (Planting, Growing, and Harvesting): cool-season crop; can survive frost and temps down to 15F (-9C); bolts as days lengthen (~14h) and temperatures reach 80F; supply 1-2 inches water per week; harvest ~37-45 days after planting.","url":"https://www.almanac.com/plant/spinach","field":"temperatureProfile"},{"citation":"Confidence note: wateringProfile.baseIntervalDays (2) is estimated from extension guidance of ~1 inch/week with the caveat that spinach is a thirsty crop that bolts if the soil dries out and that container compost dries quickly (RHS, PSU, UMN); no source gives an explicit day-interval, so a conservative 2-day interval is used for containers/warm conditions. hotWeatherMultiplier (1.5) and rainSkipThresholdMm (25 ~= 1 inch/week) are derived, not directly cited.","url":"https://www.almanac.com/plant/spinach","field":"confidence"},{"citation":"Confidence note: containerProfile liters are converted/estimated from RHS ''at least 30cm wide and deep'' (~27 L for a 30cm cube) and PSU ''adequately sized container'' for a shallow-rooted green; recommendedMinLiters (10) is a conservative practical minimum for a small baby-leaf pot, idealMin/Max (18-27) bracket the RHS 30cm guidance. No source states liters directly.","url":"https://www.rhs.org.uk/vegetables/spinach/grow-your-own","field":"confidence"},{"citation":"Confidence note: feedingProfile.baseIntervalDays (21) generalized from Clemson''s single side-dress at 3-4 weeks after planting; spinach is a short-season crop usually fed once or twice rather than on a fixed recurring interval. containerLeachAdjustment (0.5) is a derived estimate for faster nutrient leaching in pots, not directly cited.","url":"https://hgic.clemson.edu/factsheet/spinach/","field":"confidence"}]'::jsonb, 1, '2026-06-02')
